import json
from scripts.import_notion_notes import block_value

obj=json.load(open('tmp_meansparse_blocks.json',encoding='utf-8'))
blocks=obj['blocks']
root='2a884951-e962-809c-816e-d21ea6886c16'


def rich_to_text(parts):
    if not parts:
        return ''
    out=[]
    for seg in parts:
        if not isinstance(seg,list) or not seg:
            continue
        text=seg[0] if isinstance(seg[0],str) else ''
        anns=seg[1] if len(seg)>1 and isinstance(seg[1],list) else []
        replaced=False
        for ann in anns:
            if isinstance(ann,list) and ann and ann[0]=='e' and len(ann)>1:
                latex=ann[1]
                out.append(f'${latex}$')
                replaced=True
                break
            if isinstance(ann,list) and ann and ann[0]=='a' and len(ann)>1:
                href=ann[1]
                out.append(f'[{text}]({href})')
                replaced=True
                break
        if not replaced:
            out.append(text)
    return ''.join(out)


def row_cells(row_value):
    title=(row_value.get('properties') or {}).get('title') or []
    cells=[]
    for cell in title:
        if isinstance(cell,list):
            # each cell is rich text list
            cells.append(rich_to_text(cell))
        else:
            cells.append('')
    return cells

lines=[]

visited=set()
def walk(bid,depth=0):
    if bid in visited:
        return
    visited.add(bid)
    entry=blocks.get(bid,{})
    v=block_value(entry)
    t=v.get('type','unknown')
    props=v.get('properties') or {}
    pre='  '*depth

    if t=='page':
        title=rich_to_text(props.get('title'))
        lines.append(f'{pre}#PAGE {title} [{bid}]')
    elif t in {'text','bulleted_list','numbered_list','quote','sub_header','sub_sub_header','header'}:
        txt=rich_to_text(props.get('title'))
        lines.append(f'{pre}{t.upper()}: {txt}')
    elif t=='code':
        txt=rich_to_text(props.get('title'))
        lines.append(f'{pre}CODE:')
        for ln in txt.splitlines():
            lines.append(pre+'    '+ln)
    elif t=='image':
        src=rich_to_text(props.get('source'))
        title=rich_to_text(props.get('title'))
        lines.append(f'{pre}IMAGE: {title} | {src} | block={bid}')
    elif t=='table':
        lines.append(f'{pre}TABLE block={bid}')
        # render rows in child order
        for rid in v.get('content') or []:
            if not isinstance(rid,str):
                continue
            rv=block_value(blocks.get(rid,{}))
            if rv.get('type')!='table_row':
                continue
            cells=row_cells(rv)
            lines.append(pre+'  ROW: ' + ' || '.join(cells))
    elif t=='table_row':
        # skip standalone; rendered by table parent
        pass
    else:
        txt=rich_to_text(props.get('title'))
        lines.append(f'{pre}{t.upper()}: {txt} [{bid}]')

    if t!='table':
        for cid in v.get('content') or []:
            if isinstance(cid,str):
                walk(cid,depth+1)

walk(root,0)
open('tmp_meansparse_linear.md','w',encoding='utf-8').write('\n'.join(lines))
print('written',len(lines),'lines')
