import json
from scripts.import_notion_notes import block_value
obj=json.load(open('tmp_meansparse_blocks.json',encoding='utf-8'))
blocks=obj['blocks']
root='2a884951-e962-809c-816e-d21ea6886c16'

def rich_to_text(parts):
    if not parts:
        return ''
    out=[]
    for seg in parts:
        if not isinstance(seg,list) or not seg:
            continue
        text=seg[0] if isinstance(seg[0],str) else ''
        anns=seg[1] if len(seg)>1 and isinstance(seg[1],list) else []
        eq=None
        link=None
        for ann in anns:
            if isinstance(ann,list) and ann:
                if ann[0]=='e' and len(ann)>1:
                    eq=ann[1]
                    break
                if ann[0]=='a' and len(ann)>1:
                    link=ann[1]
        if eq is not None:
            out.append(f'${eq}$')
        elif link is not None:
            out.append(f'[{text}]({link})')
        else:
            out.append(text)
    return ''.join(out)

# DFS order
order=[]
seen=set()
stack=[root]
while stack:
    bid=stack.pop(0)
    if bid in seen:
        continue
    seen.add(bid)
    order.append(bid)
    v=block_value(blocks.get(bid,{}))
    for cid in v.get('content') or []:
        if isinstance(cid,str):
            stack.append(cid)

out=[]
for bid in order:
    v=block_value(blocks.get(bid,{}))
    t=v.get('type')
    props=v.get('properties') or {}
    if t in {'text','bulleted_list','numbered_list','quote','code'}:
        txt=rich_to_text(props.get('title'))
        out.append(f'[{t}] {txt}'.strip())
    elif t=='image':
        src=rich_to_text(props.get('source'))
        title=rich_to_text(props.get('title'))
        out.append(f'[image] {title} | {src} | block={bid}')
    elif t=='table':
        fmt=v.get('format') or {}
        cols=fmt.get('table_block_column_order') or []
        out.append(f'[table] block={bid} cols={cols}')
        for rid in v.get('content') or []:
            rv=block_value(blocks.get(rid,{}))
            if rv.get('type')!='table_row':
                continue
            rprops=rv.get('properties') or {}
            cells=[]
            for c in cols:
                cells.append(rich_to_text(rprops.get(c)))
            out.append('  [row] ' + ' | '.join(cells))

open('tmp_meansparse_extracted.txt','w',encoding='utf-8').write('\n'.join(out))
print('written',len(out),'lines')
